ור %1$s כבר קיים בתכונה %2$s. לא מותר עליות. שקול לצרף את הערך שלך למפתח שונה','The namespace for this manifest file has already been registered, choose a namespace other than %s'=>'התחום עבור קובץ המניפסט הזה כבר נרשם, בחר תחום אחר מאשר %s','The provided value for %1$s is not a valid url.  The url provided was: %2$s'=>'הערך שניתן עבור %1$s אינו כתובת URL חוקית. הכתובת שניתנה הייתה: %2$s','License Key for %1$s'=>'מפתח רישוי עבור %1$s','Enter your license key: '=>'הזן את מפתח הרישוי שלך: ','taxonomy general nameSeries Categories'=>'קטגוריות סדרות','taxonomy general nameSeries'=>'סדרה','taxonomy singular nameSeries Category'=>'קטגוריית סדרה','taxonomy singular nameSeries'=>'סדרה','series grouping column headerSeries'=>'סדרה','Post List Box post type name%2$s'=>'%2$s','singular post list box post type name%1$s'=>'%1$s','custom layout post type menu name%2$s'=>'%2$s','series meta box titleSeries'=>'סדרה','posts list column headerSeries'=>'סדרה','dashboard count labelSeries'=>'סדרה' . "\0" . 'סדרות' . "\0" . '' . "\0" . '','top-level admin menu labelSeries'=>'סדרה','taxonomy menu nameSeries'=>'סדרה','leave the %tokens% as is when translatingThis entry is part %series_part% of %total_posts_in_series% in the series '=>'פריט זה הוא חלק %series_part% מתוך %total_posts_in_series% בסדרה ','series list titleSeries'=>'סדרה','widget title defaultSeries'=>'סדרה','widget section labelSeries'=>'סדרה']];